import java.util.Arrays;

public class Solution {
    /**
     * Checks if array S is a cyclic shift of array T.
     * Assumes S.length == T.length = k.
     * Time complexity: O(k^2) in the naive implementation, but this is the direct approach.
     * For large k, a more advanced string matching algorithm (like KMP/hashing) would be needed for O(k).
     */
    private static boolean isCyclicShift(long[] S, long[] T) {
        int k = S.length;
        if (k == 0) return true;

        // Check all k possible rotations of T
        for (int j = 0; j < k; j++) {
            boolean match = true;
            // Check if S matches T rotated by j
            for (int l = 0; l < k; l++) {
                // The element S[l] must match T at index (l + j) modulo k
                if (S[l] != T[(l + j) % k]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }
        return false;
    }

    public static long solve(long[] nums) {
        int n = nums.length;

        // 1. Create the sorted array A
        long[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);

        long totalSum = 0;

        // 2. Find all divisors k of n
        // We only need to check up to sqrt(n)
        for (int k = 1; k * k <= n; k++) {
            if (n % k == 0) {
                // Check k
                if (isSortable(nums, sortedNums, k)) {
                    totalSum += k;
                }

                // Check n/k, provided it's not the same as k
                int k2 = n / k;
                if (k2 != k) {
                    if (isSortable(nums, sortedNums, k2)) {
                        totalSum += k2;
                    }
                }
            }
        }

        return totalSum;
    }

    /**
     * Checks if a specific divisor k makes the array sortable.
     */
    private static boolean isSortable(long[] nums, long[] sortedNums, int k) {
        int n = nums.length;
        int m = n / k; // Number of segments

        for (int i = 0; i < m; i++) {
            // Define segment start indices
            int start_nums = i * k;
            int start_sorted = i * k;

            // Extract S_i (original segment)
            long[] S_i = new long[k];
            for (int j = 0; j < k; j++) {
                S_i[j] = nums[start_nums + j];
            }

            // Extract T_i (target sorted segment)
            long[] T_i = new long[k];
            for (int j = 0; j < k; j++) {
                T_i[j] = sortedNums[start_sorted + j];
            }

            // Check the condition: S_i must be a cyclic shift of T_i
            if (!isCyclicShift(S_i, T_i)) {
                return false;
            }
        }

        return true;
    }
}

