    /**
     * Computes the Longest Proper Prefix which is also a Suffix (LPS) array for pattern P.
     * Used in KMP algorithm.
     * @param P The pattern array (integer array).
     * @param m The length of the pattern.
     * @return The LPS array.
     */
    private int[] computeLPS(long[] P, int m) {
        int[] lps = new int[m];
        int len = 0; // length of the previous longest prefix suffix
        int i = 1;
        lps[0] = 0; // lps[0] is always 0

        while (i < m) {
            if (P[i] == P[len]) {
                len++;
                lps[i] = len;
                i++;
            } else {
                if (len != 0) {
                    len = lps[len - 1];
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        return lps;
    }

    /**
     * Searches for pattern P in text T using KMP algorithm.
     * @param T The text array.
     * @param n The length of T.
     * @param P The pattern array.
     * @param m The length of P.
     * @param lps The precomputed LPS array for P.
     * @return The starting index of the first match, or -1 if no match is found.
     */
    private int searchKMP(long[] T, int n, long[] P, int m, int[] lps) {
        int i = 0; // index for T
        int j = 0; // index for P

        while (i < n) {
            if (P[j] == T[i]) {
                i++;
                j++;
            }

            if (j == m) {
                // Match found. Return the starting index.
                return i - j;
            } else if (i < n && P[j] != T[i]) {
                // Mismatch after j matches
                if (j != 0) {
                    j = lps[j - 1];
                } else {
                    i++;
                }
            }
        }
        return -1; // No match found
    }

    /**
     * Checks if array B is a cyclic shift of array S, both of length k.
     * This is achieved by checking if B is a substring of S concatenated with S (S+S).
     */
    private boolean isCyclicShift(long[] B, long[] S, int k) {
        if (k == 0) return true;

        // Construct Text T = S + S (length 2k)
        long[] T = new long[2 * k];
        for (int i = 0; i < k; i++) {
            T[i] = S[i];
            T[i + k] = S[i];
        }

        // Pattern P = B (length k)
        long[] P = B;

        // 1. Compute LPS array for P
        int[] lps = computeLPS(P, k);

        // 2. Search P in T
        // If a match is found, it means B is a cyclic shift of S.
        int matchIndex = searchKMP(T, 2 * k, P, k, lps);

        return matchIndex != -1;
    }


    public static long solve(long[] nums) {
        Solution solver = new Solution();
        int n = nums.length;
        long totalSum = 0;

        // 1. Find all divisors k of n
        List<Integer> divisors = new ArrayList<>();
        for (int k = 1; k * k <= n; k++) {
            if (n % k == 0) {
                divisors.add(k);
                if (k * k != n) {
                    divisors.add(n / k);
                }
            }
        }

        // 2. Check each divisor k
        for (int k : divisors) {
            boolean isSortable = true;

            // 2.a. Iterate through blocks
            int numBlocks = n / k;

            for (int i = 0; i < numBlocks; i++) {
                int start = i * k;

                // Extract B_i (Source Block)
                long[] Bi = new long[k];
                for (int j = 0; j < k; j++) {
                    Bi[j] = nums[start + j];
                }

                // Determine S_i (Target Block - sorted B_i)
                long[] Si = Arrays.copyOf(Bi, k);
                Arrays.sort(Si);

                // 2.b. Check cyclic shift property
                if (!solver.isCyclicShift(Bi, Si, k)) {
                    isSortable = false;
                    break;
                }
            }

            if (isSortable) {
                totalSum += k;
            }
        }

        return totalSum;
    }
