public class Solution {

    // Helper function to check if array A is a cyclic shift of array B, assuming lengths are equal.
    // This check runs in O(k^2) time, where k is the length.
    private static boolean isCyclicShift(long[] A, long[] B) {
        int k = A.length;
        if (k == 0) return true;
        if (k == 1) return A[0] == B[0];

        // Iterate through all possible starting points j in B
        for (int j = 0; j < k; j++) {
            boolean match = true;
            // Check if A matches B starting at index j, wrapping around
            for (int i = 0; i < k; i++) {
                if (A[i] != B[(j + i) % k]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }
        return false;
    }

    // Helper function to check if two arrays have the same multiset of elements.
    private static boolean multisetsMatch(long[] A, long[] B) {
        if (A.length != B.length) return false;
        if (A.length == 0) return true;

        // Since constraints allow values up to 10^5, sorting is efficient enough O(k log k)
        // given the overall complexity structure, and much simpler than using frequency maps 
        // when dealing with large long values, although here values are bounded by 10^5.
        // Sorting both and comparing is safe.
        long[] sortedA = Arrays.copyOf(A, A.length);
        long[] sortedB = Arrays.copyOf(B, B.length);
        Arrays.sort(sortedA);
        Arrays.sort(sortedB);

        return Arrays.equals(sortedA, sortedB);
    }

    public static long solve(long[] nums) {
        int n = nums.length;

        // 1. Calculate the target sorted array S
        long[] S = Arrays.copyOf(nums, n);
        Arrays.sort(S);

        long totalSumK = 0;

        // 2. Find all divisors k of n
        List<Integer> divisors = new ArrayList<>();
        for (int k = 1; k * k <= n; k++) {
            if (n % k == 0) {
                divisors.add(k);
                if (k * k != n) {
                    divisors.add(n / k);
                }
            }
        }

        // 3. Check each divisor k
        for (int k : divisors) {
            boolean isSortable = true;

            // Iterate over blocks i
            for (int i = 0; i < n / k; i++) {
                int start = i * k;

                // Extract block B_i from nums
                long[] B_i = new long[k];
                for (int j = 0; j < k; j++) {
                    B_i[j] = nums[start + j];
                }

                // Extract target block S_i from S
                long[] S_i = new long[k];
                for (int j = 0; j < k; j++) {
                    S_i[j] = S[start + j];
                }

                // Check 1: Multiset Equality
                if (!multisetsMatch(B_i, S_i)) {
                    isSortable = false;
                    break;
                }

                // Check 2: Cyclic Shift possibility
                // If multisets match, check if S_i is a cyclic shift of B_i
                if (!isCyclicShift(S_i, B_i)) {
                    isSortable = false;
                    break;
                }
            }

            if (isSortable) {
                totalSumK += k;
            }
        }

        return totalSumK;
    }
